const MS_LEVEL_COUNT = MS_LEVELS.length;

function msOriginalColorTotals(grid) {
  const totals = new Map();
  for (const v of grid) totals.set(v, (totals.get(v) || 0) + 1);
  return totals;
}
function msBucketCapacity(originalTotal) {
  return Math.max(1, Math.ceil(originalTotal * MS_BUCKET_CAPACITY_FRACTION));
}
function msGenerateLevel(levelIndex) {
  const level = MS_LEVELS[levelIndex];
  const [rows, cols] = level.g;
  const maxSlots = msColorsInLevel(level.grid).length;
  return {
    rows, cols, bandHeight: level.bh, db: level.db, maxSlots, img: level.img, grid: level.grid,
    totalByColor: msOriginalColorTotals(level.grid),
  };
}
function msColumnsFromGrid(grid, rows, cols) {
  const columns = [];
  for (let c = 0; c < cols; c++) {
    const col = [];
    for (let r = rows - 1; r >= 0; r--) col.push(grid[r * cols + c]); // bottom-up
    columns.push(col);
  }
  return columns;
}

/* ══════════════════════════════════════════════════════════
   CORE PURE LOGIC — no DOM/globals, reused verbatim by
   scripts/generate-mosaik-levels.js and scripts/verify-mosaik-levels.js
   via the module.exports guard at the bottom of this file.
══════════════════════════════════════════════════════════ */

// Reachable = bottom bandHeight cells of each column's CURRENT stack (or
// the whole column if it's shorter). Stays anchored to the visual bottom
// because gravity always keeps material bottom-packed.
function msReachableCells(columns, color, bandHeight) {
  const cells = [];
  for (let c = 0; c < columns.length; c++) {
    const col = columns[c];
    const limit = Math.min(bandHeight, col.length);
    for (let i = 0; i < limit; i++) {
      if (col[i] === color) cells.push([c, i]);
    }
  }
  return cells;
}

// Removes up to `maxCount` currently-reachable cells of `color` (all of
// them if maxCount is omitted). Returns null if nothing reachable.
function msExtractColor(columns, color, bandHeight, maxCount) {
  const cells = msReachableCells(columns, color, bandHeight);
  if (!cells.length) return null;
  const taken = maxCount != null ? cells.slice(0, maxCount) : cells;
  const removeByCol = new Map();
  for (const [c, i] of taken) {
    if (!removeByCol.has(c)) removeByCol.set(c, new Set());
    removeByCol.get(c).add(i);
  }
  const newColumns = columns.map((col, c) => {
    const removeSet = removeByCol.get(c);
    return removeSet ? col.filter((_, i) => !removeSet.has(i)) : col.slice();
  }); // SAME length as columns, always — no horizontal compaction
  return { columns: newColumns, taken: taken.length };
}

function msIsCleared(columns) { return columns.every(col => col.length === 0); }
function msColorTotalCount(columns, color) {
  let n = 0;
  for (const col of columns) for (const v of col) if (v === color) n++;
  return n;
}
function msColorsInLevel(grid) { return [...new Set(grid)].sort((a, b) => a - b); }

// The only player-facing transition: assign `color` to the given open
// slot, then cascade-drain every active slot (this one and any others,
// each capped at its own bucket capacity) until nothing more can extract
// in a pass. Pure — returns { columns, slotColor, slotFilled, removedCells }
// without mutating its inputs; removedCells is the FULL set removed across
// the whole cascade, for the caller to animate before committing. Returns
// null if the slot isn't actually open, or if `color` has nothing
// currently reachable (not a valid choice right now).
function msAssignAndResolve(columns, slotColor, slotFilled, freeSlotIdx, color, bandHeight, totalByColor) {
  if (slotColor[freeSlotIdx] != null) return null;
  if (!msReachableCells(columns, color, bandHeight).length) return null;
  let state = columns.map(col => col.slice());
  const newSlotColor = slotColor.slice();
  const newSlotFilled = slotFilled.slice();
  newSlotColor[freeSlotIdx] = color;
  newSlotFilled[freeSlotIdx] = 0;
  const removedCells = [];
  let progressed = true;
  while (progressed) {
    progressed = false;
    for (let i = 0; i < newSlotColor.length; i++) {
      const c = newSlotColor[i];
      if (c == null) continue;
      const capacity = msBucketCapacity(totalByColor.get(c));
      const remainingCapacity = capacity - newSlotFilled[i];
      if (remainingCapacity <= 0) continue; // defensive — should already have freed
      const reach = msReachableCells(state, c, bandHeight);
      if (!reach.length) continue;
      const take = reach.slice(0, remainingCapacity);
      removedCells.push(...take);
      state = msExtractColor(state, c, bandHeight, remainingCapacity).columns;
      newSlotFilled[i] += take.length;
      progressed = true;
      const colorGone = msColorTotalCount(state, c) === 0;
      if (newSlotFilled[i] >= capacity || colorGone) { newSlotColor[i] = null; newSlotFilled[i] = 0; } // bucket done — slot frees
    }
  }
  return { columns: state, slotColor: newSlotColor, slotFilled: newSlotFilled, removedCells };
}

// Stuck = every unlocked slot occupied, none of their colors has anything
// reachable, and the picture isn't cleared.
function msIsStuck(columns, slotColor, slotsUnlocked, bandHeight) {
  if (msIsCleared(columns)) return false;
  const activeSlots = slotColor.slice(0, slotsUnlocked);
  if (activeSlots.some(c => c == null)) return false; // a free slot is always a legal next action
  return activeSlots.every(c => msReachableCells(columns, c, bandHeight).length === 0);
}

/* ══════════════════════════════════════════════════════════
   GAME FLOW — reads/writes G.mosaik
══════════════════════════════════════════════════════════ */
// Transient, purely-visual state for msRender() — never persisted in G.
let msAnimating = false;   // input lock during the dissolve defer window
let msLastFallCols = null; // Set of column indices to play the "settled" cue on

function msOnColorTap(color) {
  if (msAnimating) return;
  const ms = G.mosaik;
  if (ms.currentLevelIndex == null) return;
  const level = msGenerateLevel(ms.currentLevelIndex);
  if (ms.slotColor.slice(0, ms.slotsUnlocked).includes(color)) return; // already collecting this color
  const freeSlot = ms.slotColor.findIndex((c, i) => i < ms.slotsUnlocked && c == null);
  if (freeSlot === -1) { showToast("🪣 Keine freie Behälter!"); return; }
  const result = msAssignAndResolve(ms.columns, ms.slotColor, ms.slotFilled, freeSlot, color, level.bandHeight, level.totalByColor);
  if (!result) return; // nothing of this color currently reachable — rejected, no state/visual change

  msAnimating = true;
  msPlayDissolveAnimation(result.removedCells, () => {
    msAnimating = false;
    ms.columns = result.columns;
    ms.slotColor = result.slotColor;
    ms.slotFilled = result.slotFilled;
    saveState(); // explicit — mid-level progress must survive a reload
    if (msIsCleared(ms.columns)) { msOnLevelSolved(); return; }
    if (msIsStuck(ms.columns, ms.slotColor, ms.slotsUnlocked, level.bandHeight)) {
      showToast("🧱 Feststeckt — versuch's mit 🔄 Neu starten!");
    }
    msRender();
  });
}

// Animates the currently-mounted cells about to be removed (dissolve:
// scale down + fade), then calls onDone. Marks every column that had a
// removal so msRender() can play a "just settled" cue on its survivors.
function msPlayDissolveAnimation(cells, onDone) {
  let found = false;
  const fallCols = new Set();
  cells.forEach(([c, i]) => {
    fallCols.add(c);
    const el = document.querySelector(`#ms-grid .ms-cell[data-col="${c}"][data-h="${i}"]`);
    if (el) { el.classList.add('ms-cell--dissolving'); found = true; }
  });
  msLastFallCols = fallCols;
  if (!found) { onDone(); return; }
  setTimeout(onDone, 280);
}

function msOnLevelSolved() {
  G.stats.mosaikLevelsCompleted = (G.stats.mosaikLevelsCompleted || 0) + 1;
  checkTrophies();
  showToast("🧩 Mosaik gelöst!");
  saveState();
  msRender();
  setTimeout(msAdvanceToNextLevel, 900);
}

function msAdvanceToNextLevel() {
  const ms = G.mosaik;
  ms.playOrderPos++;
  if (ms.playOrderPos >= ms.playOrder.length) {
    const prevLast = ms.playOrder[ms.playOrder.length - 1];
    const order = shuffleArray([...Array(MS_LEVEL_COUNT).keys()]);
    if (order[0] === prevLast) [order[0], order[1]] = [order[1], order[0]];
    ms.playOrder = order;
    ms.playOrderPos = 0;
  }
  msStartLevel(ms.playOrder[ms.playOrderPos]);
}

function msStartLevel(levelIndex) {
  const ms = G.mosaik;
  const level = msGenerateLevel(levelIndex);
  ms.currentLevelIndex = levelIndex;
  ms.columns = msColumnsFromGrid(level.grid, level.rows, level.cols);
  ms.slotColor = Array(level.maxSlots).fill(null);
  ms.slotFilled = Array(level.maxSlots).fill(0);
  ms.slotsUnlocked = level.db;
  msAnimating = false;
  msLastFallCols = null;
  saveState();
  msRender();
}

function msRestartLevel() {
  const ms = G.mosaik;
  if (ms.currentLevelIndex == null) return;
  msStartLevel(ms.currentLevelIndex);
  showToast("🔄 Level neu gestartet.");
}

function msEnsureQueueAndLevel() {
  const ms = G.mosaik;
  if (!ms.playOrder.length) {
    ms.playOrder = shuffleArray([...Array(MS_LEVEL_COUNT).keys()]);
    ms.playOrderPos = 0;
  }
  if (ms.currentLevelIndex == null || !ms.columns.length) {
    msStartLevel(ms.playOrder[ms.playOrderPos]);
  } else {
    msRender();
  }
}

function msBuyExtraSlot() {
  const ms = G.mosaik;
  const level = msGenerateLevel(ms.currentLevelIndex);
  if (ms.slotsUnlocked >= level.maxSlots) {
    showToast(`Maximal ${level.maxSlots} Behälter für dieses Level!`);
    return;
  }
  if (!hasActiveQuestions()) {
    showToast("Keine aktiven Fragen! Aktiviere Kapitel unter 📚.");
    return;
  }
  askQuestions("🪣 Zusatzbehälter", 1, () => {
    ms.slotsUnlocked++;
    G.stats.mosaikExtraSlotsBought = (G.stats.mosaikExtraSlotsBought || 0) + 1;
    checkTrophies();
    saveState();
    msRender();
    showToast("🪣 Neuer Behälter freigeschaltet!");
  }, null);
}

/* ══════════════════════════════════════════════════════════
   RENDERING — full innerHTML rebuild + re-bind onclick each call, per this
   app's established convention (no incremental DOM diffing anywhere).
   The grid is display-only; color swatches are the sole interaction.
══════════════════════════════════════════════════════════ */
function msRender() {
  const ms = G.mosaik;
  if (ms.currentLevelIndex == null) return;
  const level = msGenerateLevel(ms.currentLevelIndex);
  const infoEl = document.getElementById("ms-level-info");
  const imgEl = document.getElementById("ms-reference-img");
  const bucketRowEl = document.getElementById("ms-bucket-row");
  const colorRowEl = document.getElementById("ms-color-row");
  const gridEl = document.getElementById("ms-grid");
  const buyBtn = document.getElementById("ms-buy-slot-btn");
  if (!gridEl || !bucketRowEl || !colorRowEl) return;

  if (infoEl) infoEl.textContent = `Level ${ms.currentLevelIndex + 1} / ${MS_LEVEL_COUNT}`;
  if (imgEl && imgEl.getAttribute('src') !== level.img) imgEl.src = level.img;

  bucketRowEl.innerHTML = Array.from({ length: level.maxSlots }, (_, i) => {
    if (i >= ms.slotsUnlocked) return `<div class="ms-bucket-slot ms-bucket-slot--locked"></div>`;
    const color = ms.slotColor[i];
    if (color == null) return `<div class="ms-bucket-slot ms-bucket-slot--empty"></div>`;
    const capacity = msBucketCapacity(level.totalByColor.get(color));
    const filled = ms.slotFilled[i] || 0;
    const pct = Math.round((filled / capacity) * 100);
    return `<div class="ms-bucket-slot ms-bucket-slot--filled" style="background:${MS_COLORS[color]};">
      <div class="ms-bucket-fill" style="height:${pct}%"></div>
      <span class="ms-bucket-label">${filled}/${capacity}</span>
    </div>`;
  }).join("");

  const assignedColors = new Set(ms.slotColor.slice(0, ms.slotsUnlocked).filter(c => c != null));
  const availableColors = msColorsInLevel(ms.columns.flat())
    .filter(c => !assignedColors.has(c) && msReachableCells(ms.columns, c, level.bandHeight).length > 0);
  colorRowEl.innerHTML = availableColors.map(color =>
    `<button class="ms-color-swatch" style="background:${MS_COLORS[color]};" data-color="${color}"></button>`
  ).join("");
  colorRowEl.querySelectorAll(".ms-color-swatch").forEach(el => {
    el.onclick = () => msOnColorTap(parseInt(el.dataset.color, 10));
  });

  const fallCols = msLastFallCols;
  msLastFallCols = null; // consume — a later, unrelated render must not replay it

  const { rows, cols } = level;
  gridEl.style.cssText = `grid-template-columns:repeat(${cols},1fr);grid-template-rows:repeat(${rows},1fr);`;
  const cellsHtml = [];
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const stackIdx = rows - 1 - r;
      const col = ms.columns[c];
      const val = col && stackIdx < col.length ? col[stackIdx] : null;
      if (val == null) { cellsHtml.push(`<div class="ms-cell ms-cell--floor"></div>`); continue; }
      const falling = fallCols && fallCols.has(c);
      const reachable = stackIdx < level.bandHeight;
      let cls = "ms-cell";
      if (falling) cls += " ms-cell--falling";
      if (reachable) cls += " ms-cell--reachable";
      const style = falling
        ? `background:${MS_COLORS[val]};animation-delay:${stackIdx * 20}ms;`
        : `background:${MS_COLORS[val]};`;
      cellsHtml.push(`<div class="${cls}" style="${style}" data-col="${c}" data-h="${stackIdx}"></div>`);
    }
  }
  gridEl.innerHTML = cellsHtml.join("");

  if (buyBtn) {
    const atCap = ms.slotsUnlocked >= level.maxSlots;
    buyBtn.disabled = atCap;
    buyBtn.classList.toggle("ws-buy-bottle-btn--off", atCap);
    buyBtn.textContent = atCap
      ? "➕ Maximal erreicht"
      : `➕ Behälter (1 Frage) · ${ms.slotsUnlocked}/${level.maxSlots}`;
  }
}

if (typeof window !== 'undefined') {
  window.msOnColorTap = msOnColorTap;
  window.msRestartLevel = msRestartLevel;
  window.msEnsureQueueAndLevel = msEnsureQueueAndLevel;
  window.msBuyExtraSlot = msBuyExtraSlot;
  window.msRender = msRender;
}

if (typeof module !== 'undefined' && module.exports) {
  module.exports = {
    MS_COLORS, MS_LEVELS, MS_LEVEL_COUNT, MS_MAX_EXTRA_SLOTS, MS_BUCKET_CAPACITY_FRACTION,
    msGenerateLevel, msColumnsFromGrid, msOriginalColorTotals, msBucketCapacity,
    msReachableCells, msExtractColor, msIsCleared, msColorTotalCount, msColorsInLevel,
    msAssignAndResolve, msIsStuck,
  };
}
